{"code": "import json

# Get the data - businesses is a list, others are file paths
businesses = locals()['var_functions.query_db:32']
reviews_file_path = locals()['var_functions.query_db:21']
users_file_path = locals()['var_functions.query_db:20']

# Read the review and user data from files
with open(reviews_file_path, 'r') as f:
    all_reviews = json.load(f)

with open(users_file_path, 'r') as f:
    users_data = json.load(f)

# Filter to 2016 users (those with '2016' in yelping_since)
user_ids_2016 = []
for user in users_data:
    if '2016' in user.get('yelping_since', ''):
        user_ids_2016.append(user['user_id'])

# Filter reviews by 2016 users
reviews_by_2016_users = [r for r in all_reviews if r['user_id'] in user_ids_2016]

# Create mapping from business_id to categories
business_map = {}
for biz in businesses:
    business_id = biz['business_id']  # e.g., businessid_49
    description = biz.get('description', '')

    categories = []
    if description:
        # Look for categories in the description
        # Common patterns: "services in Category1, Category2, and Category3"
        # or "including Category1, Category2, and Category3"
        desc_lower = description.lower()

        # Try different patterns
        if 'services in' in desc_lower:
            category_part = description.split('services in')[1]
        elif 'including' in desc_lower:
            category_part = description.split('including')[1]
        else:
            category_part = description

        # Clean up the category part
        if ', this' in category_part:
            category_part = category_part.split(', this')[0]
        if '. ' in category_part:
            category_part = category_part.split('. ')[0]

        category_part = category_part.strip().rstrip('.')

        # Split by 'and' and ',' to get individual categories
        if ' and ' in category_part:
            # Handle "and" separately
            parts = category_part.split(' and ')
            for i, part in enumerate(parts):
                if i == 0:
                    # First part may have commas
                    subcats = part.split(',')
                    for subcat in subcats:
                        cat_clean = subcat.strip()
                        if cat_clean:
                            categories.append(cat_clean)
                else:
                    # Last part after 'and'
                    cat_clean = part.strip()
                    if cat_clean:
                        categories.append(cat_clean)
        else:
            # Just split by commas
            cats = category_part.split(',')
            for cat in cats:
                cat_clean = cat.strip()
                if cat_clean:
                    categories.append(cat_clean)

    business_map[business_id] = categories

# Count reviews per category
category_review_count = {}
for review in reviews_by_2016_users:
    business_ref = review['business_ref']  # e.g., businessref_45
    # Convert businessref_XX to businessid_XX
    business_id = business_ref.replace('businessref_', 'businessid_')

    if business_id in business_map:
        categories = business_map[business_id]
        for category in categories:
            category_review_count[category] = category_review_count.get(category, 0) + 1

# Get top 5 categories by review count
sorted_categories = sorted(category_review_count.items(), key=lambda x: x[1], reverse=True)
top_5 = sorted_categories[:5]

# Format results
result = []
for category, count in top_5:
    result.append(f"{category}: {count} reviews")

print('__RESULT__:')
print(json.dumps({
    'top_5_categories': result,
    'total_reviews_analyzed': len(reviews_by_2016_users),
    'total_unique_businesses': len(set([r['business_ref'] for r in reviews_by_2016_users])),
    'total_2016_users': len(user_ids_2016)
}))"}

