# Filter reviews by 2016 users
reviews_by_2016_users = [r for r in all_reviews if r['user_id'] in user_ids_2016]

# Better category extraction from business descriptions
business_map = {}
for biz in businesses:
    business_id = biz['business_id']
    description = biz.get('description', '')

    categories = []
    if description:
        # Find the part with categories - look for patterns
        desc_lower = description.lower()

        # Pattern 1: "services in Category1, Category2, and Category3"
        if 'services in' in desc_lower:
            category_part = description.split('services in', 1)[1]
            # Remove everything after "this facility", "this establishment", etc.
            for marker in [', this facility', ', this establishment', ', this business', ', this restaurant']:
                if marker in category_part:
                    category_part = category_part.split(marker, 1)[0]
                    break

            category_part = category_part.strip().rstrip('.')

            # Extract categories, handling "and" and commas
            if ' and ' in category_part:
                # Split by "and" first
                parts = category_part.split(' and ')
                # Process all but the last part (split by commas)
                for i in range(len(parts) - 1):
                    subparts = parts[i].split(',')
                    for subpart in subparts:
                        cat = subpart.strip()
                        if cat:
                            categories.append(cat)
                # Add the last part
                last_part = parts[-1].strip()
                if last_part:
                    categories.append(last_part)
            else:
                # Just split by commas
                cats = [c.strip() for c in category_part.split(',') if c.strip()]
                categories.extend(cats)

        # Pattern 2: "including Category1, Category2, and Category3"
        elif 'including' in desc_lower:
            category_part = description.split('including', 1)[1]
            for marker in [', this facility', ', this establishment', ', this business', ', providing']:
                if marker in category_part:
                    category_part = category_part.split(marker, 1)[0]
                    break

            category_part = category_part.strip().rstrip('.')

            # Same parsing logic for "and" and commas
            if ' and ' in category_part:
                parts = category_part.split(' and ')
                for i in range(len(parts) - 1):
                    subparts = parts[i].split(',')
                    for subpart in subparts:
                        cat = subpart.strip()
                        if cat:
                            categories.append(cat)
                last_part = parts[-1].strip()
                if last_part:
                    categories.append(last_part)
            else:
                cats = [c.strip() for c in category_part.split(',') if c.strip()]
                categories.extend(cats)

        # Pattern 3: "in Category1, Category2, and Category3"
        elif ' in ' in desc_lower:
            # Only take if it's near the end of the description
            words = description.split()
            for i, word in enumerate(words):
                if word == 'in' and i > len(words) - 10:  # "in" appears near the end
                    category_part = ' '.join(words[i+1:])
                    category_part = category_part.rstrip('.')

                    if ' and ' in category_part:
                        parts = category_part.split(' and ')
                        for i in range(len(parts) - 1):
                            subparts = parts[i].split(',')
                            for subpart in subparts:
                                cat = subpart.strip()
                                if cat:
                                    categories.append(cat)
                        last_part = parts[-1].strip()
                        if last_part:
                            categories.append(last_part)
                    else:
                        cats = [c.strip() for c in category_part.split(',') if c.strip()]
                        categories.extend(cats)
                    break

    business_map[business_id] = categories

# Count reviews per category
category_review_count = {}
for review in reviews_by_2016_users:
    business_ref = review['business_ref']
    business_id = business_ref.replace('businessref_', 'businessid_')

    if business_id in business_map:
        categories = business_map[business_id]
        for category in categories:
            # Clean up category names
            clean_category = category.strip()
            if clean_category:
                # Skip if it's just a location or other non-category text
                if not any(keyword in clean_category.lower() for keyword in ['located at', 'this facility', 'this establishment']):
                    category_review_count[clean_category] = category_review_count.get(clean_category, 0) + 1

# Get top 5 categories
sorted_categories = sorted(category_review_count.items(), key=lambda x: x[1], reverse=True)
top_5 = sorted_categories[:5]

# Format results
result_data = {
    'top_5_categories': top_5,
    'total_reviews_analyzed': len(reviews_by_2016_users),
    'total_unique_businesses': len(set([r['business_ref'] for r in reviews_by_2016_users])),
    'total_2016_users': len(user_ids_2016),
    'sample_category_counts': sorted_categories[:10]  # For debugging
}

print('__RESULT__:')
print(json.dumps(result_data))"}

