    business_id = biz['business_id']
    description = biz.get('description', '')

    categories = []
    if description:
        # Pattern 1: "including Cat1, Cat2, and Cat3."
        match1 = re.search(r'including (.*?)(?:\.|, this)', description)
        if match1:
