        match1 = re.search(r'including (.*?)(?:\.|, this)', description)
        if match1:
            cat_text = match1.group(1).strip()
            # Split by "and" and commas
            if ' and ' in cat_text:
                parts = cat_text.split(' and ')
                # Process all but last part
                for part in parts[:-1]:
                    for subcat in part.split(','):
                        cat_clean = subcat.strip()
                        if cat_clean and len(cat_clean) > 3 and not cat_clean.startswith('this'):
                            categories.append(cat_clean)
                # Last part
                last_cat = parts[-1].strip()
                if last_cat and len(last_cat) > 3 and not last_cat.startswith('this'):
                    categories.append(last_cat)
            else:
                # Only commas
                for cat in cat_text.split(','):
                    cat_clean = cat.strip()
                    if cat_clean and len(cat_clean) > 3 and not cat_clean.startswith('this'):
                        categories.append(cat_clean)

        # Pattern 2: "services in Cat1, Cat2, and Cat3."
        if not categories:
            match2 = re.search(r'services in (.*?)(?:\.|, this)', description)
            if match2:
                cat_text = match2.group(1).strip()
                if ' and ' in cat_text:
                    parts = cat_text.split(' and ')
                    for part in parts[:-1]:
                        for subcat in part.split(','):
                            cat_clean = subcat.strip()
                            if cat_clean and len(cat_clean) > 3:
                                categories.append(cat_clean)
                    last_cat = parts[-1].strip()
                    if last_cat and len(last_cat) > 3:
