                else:
                    for cat in cat_text.split(','):
                        cat_clean = cat.strip()
                        if cat_clean and len(cat_clean) > 3:
                            categories.append(cat_clean)

        # Pattern 3: "for Cat1, Cat2" (simple list)
        if not categories:
            match3 = re.search(r'for (.*?)(?:\.|, this)', description)
            if match3:
                cat_text = match3.group(1).strip()
                for cat in cat_text.split(','):
